import React, { useState, useEffect } from 'react';
import {
  Package,
  DollarSign,
  ShoppingCart,
  AlertCircle,
  TrendingUp,
  Users,
  Loader,
} from 'lucide-react';
import api from '../../services/api';

const getSaleId = (sale) => sale?.saleId ?? sale?.id ?? null;
const getSaleAmount = (sale) => Number(sale?.totalAmount ?? sale?.amount ?? 0);
const getSaleDateValue = (sale) => sale?.saleDate ?? sale?.dateCreated ?? sale?.createdDate ?? null;
const getSaleCustomerName = (sale) => {
  const directName = sale?.customerName;
  const nestedName = sale?.customer?.customerName ?? sale?.customer?.fullName;
  return directName || nestedName || 'Walk-in';
};

const formatSaleDate = (sale) => {
  const rawDate = getSaleDateValue(sale);
  if (!rawDate) return 'Unknown date';

  const parsedDate = new Date(rawDate);
  if (Number.isNaN(parsedDate.getTime())) return 'Unknown date';

  return parsedDate.toLocaleDateString();
};

const StatCard = ({ icon: Icon, title, value, subtitle, color = 'blue', trend }) => {
  const colorClasses = {
    blue: 'from-blue-400 to-blue-600',
    green: 'from-green-400 to-green-600',
    purple: 'from-purple-400 to-purple-600',
    orange: 'from-orange-400 to-orange-600',
    red: 'from-red-400 to-red-600',
  };

  return (
    <div className="p-6 transition-shadow bg-white border border-gray-200 shadow-sm rounded-xl hover:shadow-md">
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm font-medium text-gray-600">{title}</p>
          <h3 className="mt-2 text-3xl font-bold text-gray-900">{value}</h3>
          {subtitle && <p className="mt-1 text-xs text-gray-500">{subtitle}</p>}
          {trend && (
            <div className="flex items-center gap-1 mt-2">
              <TrendingUp className="w-4 h-4 text-green-500" />
              <span className="text-xs font-medium text-green-600">{trend}</span>
            </div>
          )}
        </div>
        <div className={`w-12 h-12 rounded-lg bg-gradient-to-br ${colorClasses[color]} flex items-center justify-center`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );
};

const RecentSalesTable = ({ sales, loading, error }) => {
  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader className="w-8 h-8 text-blue-500 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-4 border border-red-200 rounded-lg bg-red-50">
        <p className="text-sm text-red-700">{error}</p>
      </div>
    );
  }

  if (!sales || sales.length === 0) {
    return (
      <div className="py-12 text-center">
        <ShoppingCart className="w-12 h-12 mx-auto mb-4 text-gray-300" />
        <p className="text-gray-500">No sales data available</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full">
        <thead>
          <tr className="border-b border-gray-200">
            <th className="px-4 py-3 text-xs font-semibold tracking-wider text-left text-gray-700 uppercase">Order ID</th>
            <th className="px-4 py-3 text-xs font-semibold tracking-wider text-left text-gray-700 uppercase">Customer</th>
            <th className="px-4 py-3 text-xs font-semibold tracking-wider text-left text-gray-700 uppercase">Amount</th>
            <th className="px-4 py-3 text-xs font-semibold tracking-wider text-left text-gray-700 uppercase">Date</th>
            <th className="px-4 py-3 text-xs font-semibold tracking-wider text-left text-gray-700 uppercase">Status</th>
          </tr>
        </thead>
        <tbody>
          {sales.map((sale, index) => (
            <tr key={getSaleId(sale) ?? `sale-${index}`} className="transition-colors border-b border-gray-100 hover:bg-gray-50">
              <td className="px-4 py-3 text-sm font-medium text-gray-900">#{getSaleId(sale) ?? 'N/A'}</td>
              <td className="px-4 py-3 text-sm text-gray-600">{getSaleCustomerName(sale)}</td>
              <td className="px-4 py-3 text-sm font-semibold text-gray-900">${getSaleAmount(sale).toFixed(2)}</td>
              <td className="px-4 py-3 text-sm text-gray-600">{formatSaleDate(sale)}</td>
              <td className="px-4 py-3">
                <span className="px-3 py-1 text-xs font-medium text-green-800 bg-green-100 rounded-full">
                  Completed
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    totalProducts: 0,
    totalSales: 0,
    totalOrders: 0,
    lowStockItems: 0,
  });
  const [sales, setSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    setLoading(true);
    setError('');
    try {
      const [productsRes, salesRes] = await Promise.all([
        api.get('/products'),
        api.get('/sales') || { data: [] },
      ]);

      const products = productsRes.data || [];
      const salesData = salesRes.data || [];

      // Calculate stats
      const totalProducts = products.length;
      const lowStockCount = products.filter(p => Number(p.stockQty ?? p.stockQuantity ?? 0) < 10).length;
      const totalSales = salesData.reduce((sum, sale) => sum + getSaleAmount(sale), 0);
      const totalOrders = salesData.length;

      setStats({
        totalProducts,
        totalSales,
        totalOrders,
        lowStockItems: lowStockCount,
      });

      const recentSales = [...salesData]
        .sort((a, b) => new Date(getSaleDateValue(b) || 0) - new Date(getSaleDateValue(a) || 0))
        .slice(0, 5);

      setSales(recentSales);
    } catch (err) {
      console.error('Error fetching dashboard data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Welcome Section */}
      <div className="p-6 text-white shadow-lg bg-gradient-to-r from-blue-600 via-purple-600 to-pink-500 rounded-xl">
        <h1 className="mb-2 text-3xl font-bold">Welcome back! 👋</h1>
        <p className="text-blue-100">Here's what's happening with your store today</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4">
        <StatCard
          icon={Package}
          title="Total Products"
          value={stats.totalProducts}
          subtitle="Active items"
          color="blue"
        />
        <StatCard
          icon={DollarSign}
          title="Total Sales"
          value={`$${stats.totalSales.toFixed(2)}`}
          subtitle="This month"
          color="green"
          trend="+12.5%"
        />
        <StatCard
          icon={ShoppingCart}
          title="Total Orders"
          value={stats.totalOrders}
          subtitle="Completed"
          color="purple"
        />
        <StatCard
          icon={AlertCircle}
          title="Low Stock"
          value={stats.lowStockItems}
          subtitle="Need attention"
          color="orange"
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* Recent Sales */}
        <div className="bg-white border border-gray-200 shadow-sm lg:col-span-2 rounded-xl">
          <div className="p-6 border-b border-gray-200">
            <h2 className="text-lg font-bold text-gray-900">Recent Sales</h2>
          </div>
          <div className="p-6">
            <RecentSalesTable sales={sales} loading={loading} error={error} />
          </div>
        </div>

        {/* Quick Stats */}
        <div className="p-6 bg-white border border-gray-200 shadow-sm rounded-xl">
          <h2 className="mb-6 text-lg font-bold text-gray-900">Quick Stats</h2>
          <div className="space-y-4">
            <div className="flex items-center justify-between p-4 rounded-lg bg-blue-50">
              <span className="text-sm text-gray-700">Conversion Rate</span>
              <span className="font-bold text-blue-600">3.24%</span>
            </div>
            <div className="flex items-center justify-between p-4 rounded-lg bg-green-50">
              <span className="text-sm text-gray-700">Avg Order Value</span>
              <span className="font-bold text-green-600">${(stats.totalSales / Math.max(stats.totalOrders, 1)).toFixed(2)}</span>
            </div>
            <div className="flex items-center justify-between p-4 rounded-lg bg-purple-50">
              <span className="text-sm text-gray-700">Total Customers</span>
              <span className="font-bold text-purple-600">1,249</span>
            </div>
            <div className="flex items-center justify-between p-4 rounded-lg bg-orange-50">
              <span className="text-sm text-gray-700">Pending Orders</span>
              <span className="font-bold text-orange-600">12</span>
            </div>
          </div>
        </div>
      </div>

      {/* Refresh Button */}
      <button
        onClick={fetchDashboardData}
        disabled={loading}
        className="inline-flex items-center gap-2 px-4 py-2 text-white transition-colors bg-blue-600 rounded-lg hover:bg-blue-700 disabled:opacity-50"
      >
        {loading ? <Loader className="w-4 h-4 animate-spin" /> : null}
        Refresh Dashboard
      </button>
    </div>
  );
};

export default AdminDashboard;
